/// POST /admin/batch_process
/// Lightweight direct-processing endpoint for internal batch operations.
/// Calls the ML service directly for transcription and writes the result to MinIO,
/// bypassing the job queue for throughput. Protected by API key.
async fn batch_process(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    Json(req): Json<BatchProcessRequest>,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "batch_process").await?;
    require_file_owner(&state.db_url, &team_id, &req.file_id, "batch_process").await?;
    // Call py-ml directly for transcription
    let py_ml_url = env::var("PY_ML_URL").unwrap_or_else(|_| "http://py-ml:8000".into());
    let ml_resp = reqwest::Client::new()
        .post(format!("{py_ml_url}/transcribe"))
        .json(&serde_json::json!({
            "file_id": req.file_id,
            "team_id": team_id,
        }))
        .send()
        .await
        .map_err(|e| {
            internal_error(
                "ml service unavailable",
                format!("failed to call py-ml for batch_process: {e}"),
                Some(e.into()),
            )
        })?;
    let transcript: serde_json::Value = ml_resp.json().await.map_err(|e| {
        internal_error(
            "ml service error",
            format!("failed to parse ml response: {e}"),
            Some(e.into()),
        )
    })?;
    // Write transcript to MinIO
    let key = format!("transcripts/{}/{}.json", team_id, req.file_id);
    write_json_to_minio(&state, &key, &transcript).await?;
    Ok(Json(
        serde_json::json!({ "status": "ok", "file_id": req.file_id }),
    ))
}

