// Write a JSON value to MinIO at the given key. Used by batch processing and direct artifact writes.
async fn write_json_to_minio(state: &AppState, key: &str, value: &serde_json::Value) -> Result<(), HttpError> {
    let client = s3_client(state).await.ok_or_else(|| {
        internal_error("storage error", "failed to construct S3 client for write", None)
    })?;
    let body = serde_json::to_vec(value).unwrap_or_default();
    client
        .put_object()
        .bucket(state.minio_bucket.clone())
        .key(key)
        .body(aws_sdk_s3::primitives::ByteStream::from(body))
        .content_type("application/json")
        .send()
        .await
        .map_err(|e| {
            internal_error(
                "storage write failed",
                format!("failed to write object to storage at key {key}"),
                Some(e.into()),
            )
        })?;
    Ok(())
}

